// Запрашивает у Direct API CAMPAIGN_PERFORMANCE_REPORT за YESTERDAY.
// Через прокси-воркфлоу 18 (path /webhook/yadirect) с action='reports.get'.
// Доку: https://yandex.ru/dev/direct/doc/reports/

const yest = new Date(Date.now() - 24*3600*1000).toISOString().slice(0, 10);
const reportName = 'daily_' + yest + '_' + Date.now();

const reportBody = {
  params: {
    SelectionCriteria: {},
    FieldNames: [
      'Date',
      'CampaignId',
      'CampaignName',
      'Impressions',
      'Clicks',
      'Ctr',
      'Cost',
      'AvgCpc',
      'Conversions',
      'CostPerConversion',
      'Bounces',
      'BounceRate'
    ],
    ReportName: reportName,
    ReportType: 'CAMPAIGN_PERFORMANCE_REPORT',
    DateRangeType: 'YESTERDAY',
    Format: 'TSV',
    IncludeVAT: 'YES',
    IncludeDiscount: 'NO'
  }
};

return [{ json: { reportBody, yest, reportName } }];

// Direct API /reports возвращает TSV-таблицу с заголовком в первой строке.
// Если отчёт ещё в очереди — TSV пустой; в нашем proxy ретрай уже учтён.

const proxy = $input.first().json;
if (!proxy.ok) {
  return [{ json: { _abort: true, reason: 'proxy_error', error: proxy.error || proxy.detail || 'unknown' } }];
}

const raw = proxy.result || proxy.raw || '';
const text = typeof raw === 'string' ? raw : (raw.body || JSON.stringify(raw));

if (!text || text.length < 50) {
  return [{ json: { _abort: true, reason: 'empty_report' } }];
}

const lines = text.split(/\r?\n/).filter(l => l.trim() && !l.startsWith('Total')); // отрезаем итоговую строку, если есть
if (lines.length < 2) {
  return [{ json: { _abort: true, reason: 'no_data', sample: text.slice(0, 200) } }];
}

const header = lines[0].split('\t');
const rows = lines.slice(1).map(l => {
  const cells = l.split('\t');
  const o = {};
  header.forEach((h, i) => { o[h] = cells[i]; });
  return o;
});

function num(v) {
  if (v == null || v === '--') return 0;
  const n = parseFloat(String(v).replace(',', '.'));
  return isNaN(n) ? 0 : n;
}

// Группируем по кампании (если несколько строк за день — суммируем)
const byCampaign = {};
for (const r of rows) {
  const id = r.CampaignId || 'unknown';
  if (!byCampaign[id]) {
    byCampaign[id] = {
      id,
      name: r.CampaignName || '?',
      impressions: 0, clicks: 0, cost: 0, conversions: 0, bounces: 0, costPerConversion: null
    };
  }
  const c = byCampaign[id];
  c.impressions += num(r.Impressions);
  c.clicks      += num(r.Clicks);
  c.cost        += num(r.Cost) / 1000000; // mil → ₽
  c.conversions += num(r.Conversions);
  c.bounces     += num(r.Bounces);
}

const totals = { impressions: 0, clicks: 0, cost: 0, conversions: 0 };
for (const c of Object.values(byCampaign)) {
  c.ctr = c.impressions ? (c.clicks / c.impressions * 100) : 0;
  c.cpc = c.clicks ? (c.cost / c.clicks) : 0;
  c.cpa = c.conversions ? (c.cost / c.conversions) : null;
  c.bounceRate = c.clicks ? (c.bounces / c.clicks * 100) : 0;
  totals.impressions += c.impressions;
  totals.clicks      += c.clicks;
  totals.cost        += c.cost;
  totals.conversions += c.conversions;
}
totals.ctr = totals.impressions ? (totals.clicks / totals.impressions * 100) : 0;
totals.cpc = totals.clicks ? (totals.cost / totals.clicks) : 0;
totals.cpa = totals.conversions ? (totals.cost / totals.conversions) : null;

const yest = $('Build Report Request').first().json.yest;

return [{ json: { _abort: false, yest, campaigns: Object.values(byCampaign), totals } }];

