const data = $input.first().json;
const t = data.totals;

const campaignsList = data.campaigns.map(c =>
  '• ' + c.name + ' (id ' + c.id + ')
  показы: ' + c.impressions + ', клики: ' + c.clicks + ', CTR: ' + c.ctr.toFixed(2) + '%, CPC: ' + c.cpc.toFixed(0) + '₽, расход: ' + c.cost.toFixed(0) + '₽, конверсии: ' + c.conversions + (c.cpa ? ', CPA: ' + c.cpa.toFixed(0) + '₽' : '')
).join('

');

const sys = 'Ты директолог-аналитик. Тебе дают сводку Яндекс.Директа за вчера. Твоя задача: 1) написать короткое (3-5 строк) резюме дня в свободной форме (что произошло, что хорошо/плохо); 2) дать 1-3 КОНКРЕТНЫЕ рекомендации в JSON в конце ответа.

Ориентиры:
— здоровый CTR Поиска ≥ 0.7%, РСЯ ≥ 0.15%
— здоровый CPC для образования по РФ: 30-80₽
— если кампания съела >70% бюджета без конверсий 3+ дня — пора менять
— если CTR < 0.2% при 100+ показах — креатив или таргет плохие

Формат ответа СТРОГО:

РЕЗЮМЕ:
<3-5 строк по-русски, по-человечески, без канцелярита>

РЕКОМЕНДАЦИИ_JSON:
[{"type":"pause_campaign|raise_budget|lower_cpc|add_negative_keyword|replace_creative","campaign_id":"...","value":"...","reason":"короткое объяснение"}]

Если менять ничего не надо — массив пустой [] на отдельной строке. НЕ оборачивай JSON в markdown-фенсы.';

const userContent = 'Дата: ' + data.yest + '

Итого по аккаунту:
показы ' + t.impressions + ', клики ' + t.clicks + ', CTR ' + t.ctr.toFixed(2) + '%, CPC ' + t.cpc.toFixed(0) + '₽, расход ' + t.cost.toFixed(0) + '₽, конверсии ' + t.conversions + (t.cpa ? ', CPA ' + t.cpa.toFixed(0) + '₽' : '') + '

По кампаниям:

' + campaignsList;

const body = JSON.stringify({
  model: 'claude-haiku-4.5',
  max_tokens: 1000,
  messages: [{ role: 'user', content: sys + '

=== ДАННЫЕ ===

' + userContent }]
});

return [{ json: { body, raw: data } }];

const llmRes = $input.first().json;
const raw = $('Build LLM Body').first().json.raw;
const t = raw.totals;

let aiText = '';
if (llmRes?.choices?.[0]?.message?.content) {
  aiText = llmRes.choices[0].message.content.trim();
} else {
  aiText = '⚠️ Анализатор недоступен, показываю только сухие цифры.';
}

// Извлекаем JSON-массив рекомендаций (последний [...] в ответе)
let recommendations = [];
const m = aiText.match(/\[[\s\S]*\]/);
if (m) {
  try { recommendations = JSON.parse(m[0]); } catch(e) {}
}
// убираем JSON-блок и метку из текста для TG
const textPart = aiText.replace(/РЕКОМЕНДАЦИИ_JSON:[\s\S]*$/i, '').replace(/\[[\s\S]*\]/g, '').trim();

const hdr = `📊 *Директ-отчёт за ${raw.yest}*\n\n`;
const totalsLine = `*Итого:* показы ${t.impressions} · клики ${t.clicks} · CTR ${t.ctr.toFixed(2)}% · CPC ${t.cpc.toFixed(0)}₽ · расход ${t.cost.toFixed(0)}₽ · конверсий ${t.conversions}${t.cpa?' · CPA '+t.cpa.toFixed(0)+'₽':''}\n\n`;

const tgText = (hdr + totalsLine + textPart).slice(0, 3900); // лимит TG sendMessage

// Кнопки только если есть рекомендации
let keyboard = null;
if (recommendations.length > 0) {
  keyboard = {
    inline_keyboard: [[
      { text: '✅ Применить (' + recommendations.length + ')', callback_data: 'yd_apply:' + raw.yest },
      { text: '📊 Детали',                                  callback_data: 'yd_detail:' + raw.yest },
      { text: '🚫 Игнорировать',                            callback_data: 'yd_skip:' + raw.yest }
    ]]
  };
}

// Сохраняем рекомендации в static data — orchestrator подберёт по callback
const store = $getWorkflowStaticData('global');
if (!store.pendingRecs) store.pendingRecs = {};
store.pendingRecs[raw.yest] = { recommendations, raw, generatedAt: Date.now() };
// GC старых (старше 7 дней)
const cutoff = Date.now() - 7*24*3600*1000;
for (const k of Object.keys(store.pendingRecs)) {
  if (store.pendingRecs[k].generatedAt < cutoff) delete store.pendingRecs[k];
}

return [{ json: { tgText, keyboard, recCount: recommendations.length } }];
